// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

interface IBondToken {
    function issuer() external view returns (address);
}

/**
 * @title BondExchange
 * @notice Primary market exchange for purchasing bond tokens
 * @dev Secondary market is handled via direct P2P ERC-20 transfers (no order book).
 *      USDC payments flow directly to bond issuers — platform holds no custody.
 */
contract BondExchange is ReentrancyGuard, Ownable {
    IERC20 public immutable paymentToken;
    address public bondFactory;

    // Bond prices for primary market purchase (scaled by 1e6 for USDC decimals)
    mapping(address => uint256) public bondPrices;

    // Events
    event BondSold(
        address indexed bondToken,
        address indexed buyer,
        address indexed issuer,
        uint256 amount,
        uint256 payment,
        uint256 timestamp
    );

    /**
     * @notice Constructor
     * @param paymentToken_ Address of the USDC/payment token
     */
    constructor(address paymentToken_) Ownable(msg.sender) {
        require(paymentToken_ != address(0), "Invalid payment token");
        paymentToken = IERC20(paymentToken_);
    }

    /**
     * @notice Set the BondFactory address
     * @param factory_ Address of the BondFactory contract
     */
    function setBondFactoryAddress(address factory_) external onlyOwner {
        require(factory_ != address(0), "Invalid factory address");
        bondFactory = factory_;
    }

    /**
     * @notice Set bond price for primary market
     * @param bondToken_ Address of the bond token
     * @param price_ Price per bond token (scaled by 1e6 for USDC decimals)
     */
    function setBondPrice(address bondToken_, uint256 price_) external {
        require(msg.sender == owner() || msg.sender == bondFactory, "Not authorized");
        require(bondToken_ != address(0), "Invalid bond token");
        bondPrices[bondToken_] = price_;
    }

    /**
     * @notice Buy bond tokens from primary market
     * @dev USDC payment goes directly to bond issuer — platform holds no custody
     * @param bondToken_ Address of the bond token to buy
     * @param amount_ Amount of bond tokens to buy (scaled by 1e18)
     */
    function buyFromExchange(address bondToken_, uint256 amount_) external nonReentrant {
        require(bondToken_ != address(0), "Invalid bond token");
        require(amount_ > 0, "Amount must be positive");

        uint256 exchangeBalance = IERC20(bondToken_).balanceOf(address(this));
        require(exchangeBalance >= amount_, "Insufficient exchange balance");

        uint256 price = bondPrices[bondToken_];
        require(price > 0, "Bond price not set");

        // (price in 1e6) * (amount in 1e18) / 1e18 = USDC in 1e6
        uint256 totalPayment = (price * amount_) / 1e18;

        // Get issuer address directly from bond contract
        address issuerAddress = IBondToken(bondToken_).issuer();
        require(issuerAddress != address(0), "Invalid issuer");

        // Transfer USDC directly from buyer to issuer (no platform custody)
        require(
            paymentToken.transferFrom(msg.sender, issuerAddress, totalPayment),
            "Payment transfer failed"
        );

        // Transfer bond tokens from exchange to buyer
        require(
            IERC20(bondToken_).transfer(msg.sender, amount_),
            "Bond transfer failed"
        );

        emit BondSold(bondToken_, msg.sender, issuerAddress, amount_, totalPayment, block.timestamp);
    }
}

contracts/BondFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./BondToken.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

interface IBondExchange {
    function setBondPrice(address bondToken_, uint256 price_) external;
}

/**
 * @title BondFactory
 * @notice Factory contract for deploying independent BondToken contracts
 */
contract BondFactory is ReentrancyGuard, Ownable {
    IERC20 public immutable paymentToken;
    address public immutable bondExchange;

    address[] public deployedBonds;

    mapping(address => BondMetadata) public bondMetadata;
    mapping(address => address[]) public issuerBonds;

    struct BondMetadata {
        string name;
        string symbol;
        address issuer;
        uint256 maturityDate;
        uint256 totalSupplyCap;
        uint256 deployedAt;
        bytes32 loanAgreementHash;
        bool exists;
    }

    event BondDeployed(
        address indexed bondAddress,
        address indexed issuer,
        string name,
        string symbol,
        uint256 maturityDate,
        uint256 totalSupplyCap,
        bytes32 loanAgreementHash,
        uint256 timestamp
    );

    /**
     * @notice Constructor
     * @param paymentToken_ Address of the USDC/payment token
     * @param bondExchange_ Address of the BondExchange contract
     */
    constructor(address paymentToken_, address bondExchange_) Ownable(msg.sender) {
        require(paymentToken_ != address(0), "Invalid payment token");
        require(bondExchange_ != address(0), "Invalid bond exchange");
        paymentToken = IERC20(paymentToken_);
        bondExchange = bondExchange_;
    }

    /**
     * @notice Deploy a new bond token contract
     * @param name_ Name of the bond
     * @param symbol_ Symbol of the bond token
     * @param issuer_ Address of the bond issuer
     * @param maturityDate_ Unix timestamp of maturity date
     * @param totalSupplyCap_ Maximum supply of bond tokens
     * @param pricePerToken_ Price per token in USDC (scaled by 1e6)
     * @param loanAgreementHash_ SHA-256 hash of the signed Loan Agreement (must not be zero)
     * @return bondAddress Address of the newly deployed bond contract
     */
    function createBond(
        string memory name_,
        string memory symbol_,
        address issuer_,
        uint256 maturityDate_,
        uint256 totalSupplyCap_,
        uint256 pricePerToken_,
        bytes32 loanAgreementHash_
    ) external nonReentrant returns (address bondAddress) {
        require(issuer_ != address(0), "Invalid issuer address");
        require(maturityDate_ > block.timestamp, "Maturity must be in future");
        require(totalSupplyCap_ > 0, "Supply cap must be positive");
        require(bytes(name_).length > 0, "Name cannot be empty");
        require(bytes(symbol_).length > 0, "Symbol cannot be empty");
        require(loanAgreementHash_ != bytes32(0), "Loan Agreement must be signed before deployment");

        BondToken newBond = new BondToken(
            name_,
            symbol_,
            address(paymentToken),
            issuer_,
            maturityDate_,
            totalSupplyCap_,
            loanAgreementHash_
        );

        bondAddress = address(newBond);

        newBond.mint(bondExchange, totalSupplyCap_);

        IBondExchange(bondExchange).setBondPrice(bondAddress, pricePerToken_);

        newBond.transferOwnership(issuer_);

        bondMetadata[bondAddress] = BondMetadata({
            name: name_,
            symbol: symbol_,
            issuer: issuer_,
            maturityDate: maturityDate_,
            totalSupplyCap: totalSupplyCap_,
            deployedAt: block.timestamp,
            loanAgreementHash: loanAgreementHash_,
            exists: true
        });

        deployedBonds.push(bondAddress);
        issuerBonds[issuer_].push(bondAddress);

        emit BondDeployed(
            bondAddress,
            issuer_,
            name_,
            symbol_,
            maturityDate_,
            totalSupplyCap_,
            loanAgreementHash_,
            block.timestamp
        );

        return bondAddress;
    }


    function getAllBonds() external view returns (address[] memory) {
        return deployedBonds;
    }

    function getBondsByIssuer(address issuer_) external view returns (address[] memory) {
        return issuerBonds[issuer_];
    }

    function getBondCount() external view returns (uint256) {
        return deployedBonds.length;
    }

    function isBond(address bondAddress_) external view returns (bool) {
        return bondMetadata[bondAddress_].exists;
    }

    function getBondMetadata(address bondAddress_) external view returns (BondMetadata memory) {
        require(bondMetadata[bondAddress_].exists, "Bond does not exist");
        return bondMetadata[bondAddress_];
    }
}

contracts/BondToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title BondToken
 * @notice ERC20 token representing a tokenized bond with yield distribution and maturity
 * @dev Each bond is backed by a signed Loan Agreement — its SHA-256 hash is stored on-chain
 */
contract BondToken is ERC20, ReentrancyGuard, Ownable {
    IERC20 public immutable paymentToken;

    uint256 public immutable maturityDate;
    uint256 public immutable totalSupplyCap;
    address public immutable issuer;

    // SHA-256 hash of the signed Loan Agreement — set once at deployment, immutable thereafter
    bytes32 public loanAgreementHash;

    uint256 public totalYieldDeposited;
    uint256 public totalPrincipalDeposited;

    bool public isMatured;
    bool public principalDeposited;

    struct YieldCheckpoint {
        uint256 totalYield;
        uint256 totalSupplySnapshot;
        uint256 timestamp;
    }

    YieldCheckpoint[] public yieldCheckpoints;
    mapping(address => uint256) public lastClaimedCheckpoint;

    // Events
    event YieldDeposited(uint256 amount, uint256 checkpointIndex, uint256 timestamp);
    event YieldClaimed(address indexed holder, uint256 amount);
    event PrincipalDeposited(uint256 amount, uint256 timestamp);
    event PrincipalClaimed(address indexed holder, uint256 bondsBurned, uint256 principalAmount);
    event BondMinted(address indexed to, uint256 amount);
    event LoanAgreementSet(bytes32 indexed hash, uint256 timestamp);

    constructor(
        string memory name_,
        string memory symbol_,
        address paymentToken_,
        address issuer_,
        uint256 maturityDate_,
        uint256 totalSupplyCap_,
        bytes32 loanAgreementHash_
    ) ERC20(name_, symbol_) Ownable(msg.sender) {
        require(paymentToken_ != address(0), "Invalid payment token");
        require(issuer_ != address(0), "Invalid issuer");
        require(maturityDate_ > block.timestamp, "Maturity must be in future");
        require(totalSupplyCap_ > 0, "Supply cap must be positive");
        require(loanAgreementHash_ != bytes32(0), "Loan agreement must be signed before deployment");

        paymentToken = IERC20(paymentToken_);
        issuer = issuer_;
        maturityDate = maturityDate_;
        totalSupplyCap = totalSupplyCap_;
        loanAgreementHash = loanAgreementHash_;

        emit LoanAgreementSet(loanAgreementHash_, block.timestamp);
    }

    /**
     * @notice Update the Loan Agreement hash (only callable by owner/issuer)
     * @param hash_ SHA-256 hash of the signed Loan Agreement
     */
    function setLoanAgreementHash(bytes32 hash_) external onlyOwner {
        require(hash_ != bytes32(0), "Hash cannot be zero");
        require(loanAgreementHash == bytes32(0), "Loan Agreement hash already set and cannot be changed");
        loanAgreementHash = hash_;
        emit LoanAgreementSet(hash_, block.timestamp);
    }

    function mint(address to, uint256 amount) external onlyOwner {
        require(totalSupply() + amount <= totalSupplyCap, "Exceeds supply cap");
        require(!isMatured, "Bond has matured");
        _mint(to, amount);
        emit BondMinted(to, amount);
    }

    /**
     * @notice Deposit yield for bondholders (anyone can contribute to the yield pool)
     * @param amount Amount of USDC to deposit as yield
     */
    function depositYield(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be positive");
        require(totalSupply() > 0, "No bonds issued yet");

        // Transfer payment token from issuer
        require(
            paymentToken.transferFrom(msg.sender, address(this), amount),
            "Transfer failed"
        );

        // Create new yield checkpoint
        yieldCheckpoints.push(YieldCheckpoint({
            totalYield: amount,
            totalSupplySnapshot: totalSupply(),
            timestamp: block.timestamp
        }));

        totalYieldDeposited += amount;

        emit YieldDeposited(amount, yieldCheckpoints.length - 1, block.timestamp);
    }

    /**
     * @notice Calculate unclaimed yield for a holder
     * @param holder Address of the bondholder
     * @return Total unclaimed yield amount
     */
    function getUnclaimedYield(address holder) public view returns (uint256) {
        uint256 unclaimedYield = 0;
        uint256 holderBalance = balanceOf(holder);

        if (holderBalance == 0) return 0;

        uint256 startCheckpoint = lastClaimedCheckpoint[holder];

        for (uint256 i = startCheckpoint; i < yieldCheckpoints.length; i++) {
            YieldCheckpoint memory checkpoint = yieldCheckpoints[i];
            // Proportional yield based on balance at checkpoint time
            unclaimedYield += (checkpoint.totalYield * holderBalance) / checkpoint.totalSupplySnapshot;
        }

        return unclaimedYield;
    }

    /**
     * @notice Claim accumulated yield (pull pattern)
     */
    function claimYield() external nonReentrant {
        uint256 claimableYield = getUnclaimedYield(msg.sender);
        require(claimableYield > 0, "No yield to claim");

        // Update last claimed checkpoint
        lastClaimedCheckpoint[msg.sender] = yieldCheckpoints.length;

        // Transfer yield to holder
        require(
            paymentToken.transfer(msg.sender, claimableYield),
            "Yield transfer failed"
        );

        emit YieldClaimed(msg.sender, claimableYield);
    }

    /**
     * @notice Mark bond as matured (automatic after maturity date)
     */
    function checkMaturity() public {
        if (!isMatured && block.timestamp >= maturityDate) {
            isMatured = true;
        }
    }

    /**
     * @notice Deposit principal for maturity redemption (only callable by issuer)
     * @param amount Total principal amount in USDC
     */
    function depositPrincipal(uint256 amount) external onlyOwner nonReentrant {
        checkMaturity();
        require(isMatured, "Bond not yet matured");
        require(!principalDeposited, "Principal already deposited");
        require(amount > 0, "Amount must be positive");

        // Transfer principal from issuer
        require(
            paymentToken.transferFrom(msg.sender, address(this), amount),
            "Transfer failed"
        );

        totalPrincipalDeposited = amount;
        principalDeposited = true;

        emit PrincipalDeposited(amount, block.timestamp);
    }

    /**
     * @notice Claim principal at maturity and burn bond tokens
     */
    function claimPrincipal() external nonReentrant {
        checkMaturity();
        require(isMatured, "Bond not yet matured");
        require(principalDeposited, "Principal not deposited by issuer");

        uint256 holderBalance = balanceOf(msg.sender);
        require(holderBalance > 0, "No bonds to redeem");

        // Calculate proportional principal
        uint256 principalAmount = (totalPrincipalDeposited * holderBalance) / totalSupply();

        // Burn bond tokens
        _burn(msg.sender, holderBalance);

        // Transfer principal to holder
        require(
            paymentToken.transfer(msg.sender, principalAmount),
            "Principal transfer failed"
        );

        emit PrincipalClaimed(msg.sender, holderBalance, principalAmount);
    }

    function getBondInfo() external view returns (
        uint256 _maturityDate,
        uint256 _totalSupply,
        uint256 _totalSupplyCap,
        uint256 _totalYieldDeposited,
        uint256 _totalPrincipalDeposited,
        bool _isMatured,
        bool _principalDeposited,
        uint256 _checkpointCount,
        bytes32 _loanAgreementHash
    ) {
        return (
            maturityDate,
            totalSupply(),
            totalSupplyCap,
            totalYieldDeposited,
            totalPrincipalDeposited,
            isMatured || block.timestamp >= maturityDate,
            principalDeposited,
            yieldCheckpoints.length,
            loanAgreementHash
